# ============================================================================
# Panel 7 (CC 2.1.126) — invocation_trigger breakdown
# ============================================================================

test_panel7_returns_array() {
  local out
  out=$(jq -s 'map(select(.invocation_trigger != null))
    | group_by(.skill_name)
    | map({
        skill: .[0].skill_name,
        total: length,
        user_slash: (map(select(.invocation_trigger == "user-slash")) | length),
        claude_proactive: (map(select(.invocation_trigger == "claude-proactive")) | length),
        nested_skill: (map(select(.invocation_trigger == "nested-skill")) | length),
        proactive_ratio: ((map(select(.invocation_trigger == "claude-proactive")) | length) / length * 100 | floor)
      })
    | sort_by(-.total)' "$FIX/skill-activated.jsonl")

  local count
  count=$(echo "$out" | jq 'length')
  if [[ "$count" == "5" ]]; then
    log_pass "Panel 7: 5 skills aggregated"
  else
    log_fail "Panel 7 skill count" "expected 5, got $count"
    return
  fi

  local ratio
  ratio=$(echo "$out" | jq -r '.[] | select(.skill == "frontend-design") | .proactive_ratio')
  if [[ "$ratio" == "60" ]]; then
    log_pass "Panel 7: frontend-design proactive_ratio = 60"
  else
    log_fail "Panel 7 proactive_ratio" "expected 60, got $ratio"
  fi

  local nested
  nested=$(echo "$out" | jq -r '.[] | select(.skill == "ork:component-search") | .nested_skill')
  if [[ "$nested" == "2" ]]; then
    log_pass "Panel 7: component-search nested_skill = 2"
  else
    log_fail "Panel 7 nested count" "expected 2, got $nested"
  fi
}
test_panel7_returns_array

# ============================================================================
# Panel 8 (CC 2.1.122) — at_mention top targets
# ============================================================================

test_panel8_top_targets() {
  local out
  out=$(jq -s 'map(select(.target != null))
    | group_by(.target)
    | map({target: .[0].target, count: length})
    | sort_by(-.count)
    | .[0:20]' "$FIX/at-mentions.jsonl")

  local first
  first=$(echo "$out" | jq -r '.[0].target')
  if [[ "$first" == "CLAUDE.md" ]]; then
    log_pass "Panel 8: top target = CLAUDE.md (count 3)"
  else
    log_fail "Panel 8 top target" "expected CLAUDE.md, got $first"
  fi

  local first_count
  first_count=$(echo "$out" | jq -r '.[0].count')
  if [[ "$first_count" == "3" ]]; then
    log_pass "Panel 8: top count = 3"
  else
    log_fail "Panel 8 top count" "expected 3, got $first_count"
  fi
}
test_panel8_top_targets

# ============================================================================
# Graceful fallback — when CC < target version recorded no events of the
# matching type, the file exists but has zero matches after filter. Test that
# the documented jq queries still emit [] cleanly (no errors, no crashes).
# Tests EMPTY-file case rather than missing-file, so jq runs normally without
# stderr suppression — any real query syntax errors will surface.
# ============================================================================

test_panel7_empty_file_returns_empty() {
  local empty="$FIX/empty-fixture.jsonl"
  : > "$empty"   # truncate to zero bytes
  local out
  out=$(jq -s 'map(select(.invocation_trigger != null))
    | group_by(.skill_name)
    | map({skill: .[0].skill_name, total: length})' "$empty")
  rm -f "$empty"
  if [[ "$out" == "[]" ]]; then
    log_pass "Panel 7: empty file produces []"
  else
    log_fail "Panel 7 empty-file fallback" "expected [], got '$out'"
  fi
}
test_panel7_empty_file_returns_empty

test_panel8_empty_file_returns_empty() {
  local empty="$FIX/empty-fixture.jsonl"
  : > "$empty"
  local out
  out=$(jq -s 'map(select(.target != null))
    | group_by(.target)
    | map({target: .[0].target, count: length})
    | sort_by(-.count)
    | .[0:20]' "$empty")
  rm -f "$empty"
  if [[ "$out" == "[]" ]]; then
    log_pass "Panel 8: empty file produces []"
  else
    log_fail "Panel 8 empty-file fallback" "expected [], got '$out'"
  fi
}
test_panel8_empty_file_returns_empty

# ============================================================================
# Path-decode fix — stale-project detection must NOT use lossy sed decode
# (M129 Item 2: replaces sed-based collapse with claude project purge dry-run parsing)
# ============================================================================

test_dream_no_lossy_decode() {
  # Detect the buggy pipeline shape (printf | sed s|-|/|g) used as actual code.
  # The pattern appears in prose-as-example with single backticks but never with `printf` adjacent.
  if grep -qE "printf.*sed.*s\|-\|/\|g" "$PROJECT_ROOT/src/skills/dream/SKILL.md"; then
    log_fail "dream SKILL.md still uses lossy sed decode pipeline" "see STEP 8"
  else
    log_pass "dream SKILL.md does not use lossy sed decode pipeline"
  fi
}
test_dream_no_lossy_decode

test_doctor_no_lossy_decode() {
  if grep -qE "printf.*sed.*s\|-\|/\|g" "$PROJECT_ROOT/src/skills/doctor/rules/diagnostic-checks.md"; then
    log_fail "doctor diagnostic-checks.md still uses lossy sed decode pipeline" "see Category 14"
  else
    log_pass "doctor diagnostic-checks.md does not use lossy sed decode pipeline"
  fi
}
test_doctor_no_lossy_decode

test_dream_uses_proper_source() {
